291	function statusForOutcome(outcome: string): CliStatus {
292	  switch (outcome) {
293	    case "ready":
294	    case "ready-for-verification":
295	    case "needs-followup-fix":
296	    case "pass":
297	    case "revise":
298	    case "cleaned":
299	    case "needs-more-cleanup":
300	    case "ready-for-closeout":
301	    case "needs-fixes":
302	    case "needs-more-routing":
303	    case "needs-more-verification":
304	      return "ok";
305	    case "block":
306	      return "blocked";
307	    case "needs-user-decision":
308	    case "needs-human-ruling":
309	      return "needs-user-decision";
310	    case "blocked":
311	      return "blocked";
312	    default:
313	      return "error";
314	  }
315	}
