   407	export interface CliRunResult {
   408	  exitCode: number;
   409	  stdout: string;
   410	  stderr: string;
   411	}
   412	
   413	export async function runSourceCli(
   414	  args: string[],
   415	  options: {
   416	    env?: Record<string, string | undefined>;
   417	  } = {}
   418	): Promise<CliRunResult> {
   419	  const proc = Bun.spawn(["bun", "run", "processes/impl-cli/cli.ts", ...args], {
   420	    cwd: ROOT,
   421	    stdout: "pipe",
   422	    stderr: "pipe",
   423	    env: {
   424	      ...process.env,
   425	      ...options.env,
   426	      FORCE_COLOR: "0",
   427	    },
   428	  });
   429	
   430	  const stdout = await new Response(proc.stdout).text();
   431	  const stderr = await new Response(proc.stderr).text();
   432	  const exitCode = await proc.exited;
   433	
   434	  return {
   435	    exitCode,
   436	    stdout,
   437	    stderr,
   438	  };
   439	}
   440	
   441	export function parseJsonOutput<T>(stdout: string): T {
   442	  return JSON.parse(stdout.trim()) as T;
   443	}

